-- ============================================
-- 天津2026年高考一分一段表数据导入
-- 数据来源：天津市教育招生考试院2026年6月24日官方发布
-- 本科线：458分（累计52753人）
-- 特招线：547分（累计24370人）
-- 680分及以上：197人
-- 300分及以上：77488人
-- ============================================

-- 第一步：清理旧的天津2026年数据（如有）
DELETE FROM score_distribution WHERE province = '天津' AND year = 2026;

-- 第二步：批量插入天津2026年一分一段表数据

-- 第三步：验证数据
SELECT province, year, COUNT(*) as records, MIN(score) as min_score, MAX(score) as max_score, MAX(cumulative_count) as total_students FROM score_distribution WHERE province = '天津' AND year = 2026 GROUP BY province, year;